import React from 'react';
import { useNavigate } from 'react-router-dom';

export default function Welcome() {
  const navigate = useNavigate();

  return (
    <div className="flex items-center justify-center min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
      <div className="w-full max-w-md p-10 text-center bg-white shadow-xl rounded-2xl">
        <h1 className="mb-4 text-3xl font-bold text-indigo-700">Welcome to Exam Portal</h1>
        <p className="mb-8 text-gray-600">Please choose your login type</p>

        <div className="space-y-4">
          <button
            onClick={() => navigate('/user-login')}
            className="w-full px-4 py-2 text-white transition bg-indigo-600 rounded-xl hover:bg-indigo-700"
          >
            User Login
          </button>

          <button
            onClick={() => navigate('/admin-login')}
            className="w-full px-4 py-2 text-white transition bg-blue-600 rounded-xl hover:bg-blue-700"
          >
            Admin Login
          </button>
        </div>
      </div>
    </div>
  );
}
